#!/bin/bash

# MySQL Database Backup Script

# --- Configuration ---
DB_HOST="localhost"
DB_USER="backup_user"
DB_PASS="BackupPass123" # Use single quotes to protect special characters

BACKUP_DIR="/var/backups/mysql"
DATE_FORMAT="%Y-%m-%d_%H-%M-%S"
LOG_FILE="${BACKUP_DIR}/backup_log.log"

# --- Script Logic ---

# Create backup directory if it doesn't exist
mkdir -p "$BACKUP_DIR"

# Ensure the log file exists
touch "$LOG_FILE"

echo "----------------------------------------------------" >> "$LOG_FILE"
echo "Backup started: $(date +"$DATE_FORMAT")" >> "$LOG_FILE"

# Get a list of all databases, excluding system databases
# The 'mysql' command needs the password provided via -p'password' or read from stdin,
# or via .my.cnf. For this specific request, it's directly in the command.
DATABASES=$(mysql -h "$DB_HOST" -u "$DB_USER" -p"$DB_PASS" -e "SHOW DATABASES;" | \
            grep -Ev "(Database|information_schema|performance_schema|mysql|sys)")

if [ -z "$DATABASES" ]; then
    echo "ERROR: No databases found or unable to connect to MySQL." >> "$LOG_FILE"
    echo "Backup finished: $(date +"$DATE_FORMAT") with errors." >> "$LOG_FILE"
    exit 1
fi

for DB in $DATABASES; do
    echo "Backing up database: $DB" >> "$LOG_FILE"
    BACKUP_FILE="${BACKUP_DIR}/${DB}_$(date +"$DATE_FORMAT").sql"

    # Execute mysqldump
    if mysqldump -h "$DB_HOST" -u "$DB_USER" -p"$DB_PASS" "$DB" > "$BACKUP_FILE"; then
        echo "Successfully backed up $DB to $BACKUP_FILE" >> "$LOG_FILE"
    else
        echo "ERROR: Failed to backup $DB" >> "$LOG_FILE"
    fi
done

echo "Backup finished: $(date +"$DATE_FORMAT")" >> "$LOG_FILE"
echo "----------------------------------------------------" >> "$LOG_FILE"

# You might want to add commands here to compress or prune old backups
# Example for compression (optional):
# find "$BACKUP_DIR" -type f -name "*.sql" -exec gzip {} \;

# Example for pruning old backups (e.g., keep last 7 days) (optional):
# find "$BACKUP_DIR" -type f -mtime +7 -delete

exit 0